226→/**
227→ * Expands the input area and moves cursor to the end (for keyboard shortcut)
228→ */
229→export function expandInputWithCursorAtEnd(): void {
230→  const container = getInputContainer();
231→  if (!container) return;
232→  expand(container, true); // true = move cursor to end
233→}
