235→/**
236→ * Collapses the input area immediately (for keyboard shortcut)
237→ * This bypasses the delay and state checks in tryCollapse
238→ */
239→export function collapseInput(): void {
240→  const container = getInputContainer();
241→  if (!container) return;
242→
243→  // Immediately collapse (ignore delay and state checks)
244→  container.classList.add(COLLAPSED_CLASS);
245→
246→  // Remove focus from the input
247→  const active = document.activeElement;
248→  if (active && container.contains(active)) {
249→    (active as HTMLElement).blur();
250→  }
251→}
