253→/**
254→ * Checks if the input is effectively empty.
255→ */
256→function isInputEmpty(container: HTMLElement): boolean {
257→  // Check the text content of the rich-textarea
258→  const textarea =
259→    container.querySelector('rich-textarea') ||
260→    container.querySelector('textarea') ||
261→    container.querySelector('[contenteditable="true"]');
262→  if (!textarea) return true;
263→
264→  // Check for attachments. If attachments exist, the input is not considered empty.
265→  const attachmentsArea =
266→    container.querySelector('uploader-file-preview') ||
267→    container.querySelector('.file-preview-wrapper');
268→  if (attachmentsArea) return false;
269→
270→  const text = textarea.textContent?.trim() || '';
271→  return text.length === 0;
272→}
