274→/**
275→ * Adds the placeholder element to the container if it doesn't exist.
276→ */
277→function ensurePlaceholder(container: HTMLElement) {
278→  if (container.querySelector(`.${PLACEHOLDER_CLASS}`)) return;
279→
280→  const placeholder = document.createElement('div');
281→  placeholder.className = PLACEHOLDER_CLASS;
