296→export function startInputCollapse() {
297→  // Check if feature is enabled (default: false)
298→  chrome.storage?.sync?.get(
299→    { gvInputCollapseEnabled: false, gvInputCollapseWhenNotEmpty: false },
300→    (res) => {
301→      if (res?.gvInputCollapseEnabled === false) {
302→        // Feature is disabled, don't initialize
303→        console.log('[Gemini Voyager] Input collapse is disabled');
304→        return;
305→      }
306→
307→      // Feature is enabled, proceed with initialization
308→      initInputCollapse(res?.gvInputCollapseWhenNotEmpty === true);
309→    },
310→  );
311→
312→  // Listen for setting changes
313→  chrome.storage?.onChanged?.addListener((changes, area) => {
314→    if (
315→      area === 'sync' &&
316→      (changes.gvInputCollapseEnabled || changes.gvInputCollapseWhenNotEmpty)
317→    ) {
318→      if (changes.gvInputCollapseEnabled?.newValue === false) {
319→        // Disable: remove styles and classes
320→        cleanup();
321→      }
322→    } else {
323→      // Enable or setting changed: re-read both settings and re-initialize
324→      chrome.storage?.sync?.get({ gvInputCollapseWhenNotEmpty: false }, (res) => {
325→        allowCollapseWhenNotEmpty = res?.gvInputCollapseWhenNotEmpty === true;
326→
327→        initInputCollapse(allowCollapseWhenNotEmpty);
328→      });
329→    }
330→  });
331→}
332→
333→let observer: MutationObserver | null = null;
334→let initialized = false;
335→let eventController: AbortController | null = null;
336→let allowCollapseWhenNotEmpty = false; // Track the "collapse when not empty" setting
337→let collapseTimer: number | null = null; // Timer for delayed collapse
338→
339→/**
340→ * Cleans up the input collapse feature.
341→ * Removes all event listeners, styles, and resets state.
342→ * Exported for testing purposes.
343→ */
344→export function cleanup() {
345→  // Clear any pending collapse timer
346→  if (collapseTimer !== null) {
347→    clearTimeout(collapseTimer);
348→    collapseTimer = null;
349→  }
350→
351→  // Abort all event listeners managed by the controller
352→  if (eventController) {
353→    eventController.abort();
354→    eventController = null;
355→  }
356→
357→  // Remove styles
358→  const style = document.getElementById(STYLE_ID);
359→  if (style) style.remove();
360→
361→  // Remove classes from containers
362→  document.querySelectorAll(`.${COLLAPSED_CLASS}`).forEach((el) => {
363→    el.classList.remove(COLLAPSED_CLASS);
364→  });
365→  document.querySelectorAll('.element-to-collapse').forEach((el) => {
366→    el.classList.remove('element-to-collapse');
367→  });
368→  document.querySelectorAll('.gv-processed').forEach((el) => {
369→    el.classList.remove('gv-processed');
370→  });
371→  document.querySelectorAll(`.${PLACEHOLDER_CLASS}`).forEach((el) => {
372→    el.remove();
373→  });
374→
375→  // Disconnect observer
376→  if (observer) {
377→    observer.disconnect();
378→    observer = null;
379→  }
380→
381→  initialized = false;
382→}
383→
384→function initInputCollapse(allowCollapseNotEmpty: boolean = false) {
385→  if (initialized) return;
386→  initialized = true;
387→  allowCollapseWhenNotEmpty = allowCollapseNotEmpty; // Store the setting
388→
389→  injectStyles();
390→
391→  let lastPathname = window.location.pathname;
392→
393→  // Create AbortController for managing all event listeners
394→  eventController = new AbortController();
395→  const { signal } = eventController;
396→
397→  // Auto-expand the input area when a file is dragged into the window.
398→  document.addEventListener(
399→    'dragenter',
400→    (e) => {
401→      if (e.dataTransfer?.types.includes('Files')) {
402→        const container = getInputContainer();
403→        if (container && container.classList.contains(COLLAPSED_CLASS)) {
404→          expand(container);
405→        }
406→      }
407→    },
408→    { signal, capture: true },
409→  );
410→
411→  // Handle URL changes for SPA navigation
412→  const urlChangeHandler = () => {
413→    // Safety check for test environments and edge cases
414→    if (typeof window === 'undefined' || !window.location) return;
415→
416→    const currentPathname = window.location.pathname;
417→    if (currentPathname === lastPathname) return;
418→
419→    lastPathname = currentPathname;
420→
421→    const container = getInputContainer();
422→    if (!container) return;
423→
424→    if (shouldDisableAutoCollapse()) {
425→      // On homepage/new conversation/gems create: expand the input
426→      container.classList.remove(COLLAPSED_CLASS);
427→    } else {
428→      // On conversation page: try to collapse if appropriate
429→      tryCollapse(container);
430→    }
431→  };
432→
433→  // Listen for URL changes (browser back/forward)
434→  window.addEventListener('popstate', urlChangeHandler, { signal });
435→
436→  // MutationObserver to re-apply when Gemini re-renders and detect SPA navigation
437→  // Use MutationObserver so we re-apply if Gemini re-renders (common in SPAs)
438→  observer = new MutationObserver(() => {
439→    // Check for URL changes on DOM mutations (catches SPA navigation)
440→    urlChangeHandler?.();
441→
442→    const container = getInputContainer();
443→    if (container && !container.classList.contains('gv-processed')) {
444→      container.classList.add('gv-processed');
445→      container.classList.add('element-to-collapse'); // Add transition class
446→
447→      ensurePlaceholder(container);
448→
449→      // Events - use signal for automatic cleanup
450→      container.addEventListener(
451→        'click',
452→        () => {
453→          expand(container);
454→        },
455→        { signal },
456→      );
457→
458→      // Capture focus events deeply
459→      // focusin cancels delayed collapse when focus returns to input area
460→      container.addEventListener(
461→        'focusin',
462→        () => {
463→          expand(container);
464→          // If we have a pending collapse, cancel it since focus is coming back
465→          if (collapseTimer !== null) {
466→            clearTimeout(collapseTimer);
467→            collapseTimer = null;
468→          }
469→        },
470→        { signal },
471→      );
472→
473→      // Store container reference for use in closures
474→      const currentContainer = container;
475→
476→      container.addEventListener(
477→        'focusout',
478→        (e) => {
479→          // Clear any existing timer
480→          if (collapseTimer !== null) {
481→            clearTimeout(collapseTimer);
482→            collapseTimer = null;
483→          }
484→
485→          const newFocus = e.relatedTarget as HTMLElement;
486→
487→          // Check if focus is still inside the container
488→          if (newFocus && currentContainer.contains(newFocus)) {
489→            return; // Focus is still inside
490→          }
491→
492→          // Use a small delay before collapsing
493→          // This allows focusin events to cancel the collapse if focus returns
494→          collapseTimer = window.setTimeout(() => {
495→            // Double-check: focus should truly be away from input-related elements
496→            const active = document.activeElement;
497→            if (active && currentContainer.contains(active)) {
498→              return; // Focus came back, don't collapse
499→            }
500→
501→            // Also check if the new focus is in an input-related overlay/menu
502→            if (newFocus && isInputRelatedElement(newFocus, currentContainer)) {
503→              return; // Focus moved to input-related UI, don't collapse
504→            }
505→
506→            // Now safe to collapse
507→            tryCollapse(currentContainer);
508→            collapseTimer = null;
509→          }, 50); // 50ms delay - enough for focusin to cancel if needed
510→        },
511→        { signal },
512→      );
513→
514→      // Initial check - only collapse if not on excluded pages
515→      if (!shouldDisableAutoCollapse()) {
516→        tryCollapse(container);
517→      }
518→    }
519→  });
520→
521→  observer.observe(document.body, { childList: true, subtree: true });
522→
523→  // Add keyboard shortcuts for collapse/expand
524→  document.addEventListener(
525→    'keydown',
526→    (e) => {
527→      const container = getInputContainer();
528→      if (!container) return;
529→
530→      // ESC key - collapse input
531→      if (e.key === 'Escape') {
532→        // Only respond when focus is within the input container
533→        const active = document.activeElement;
534→        if (active && container.contains(active)) {
535→          e.preventDefault();
536→          e.stopPropagation();
537→          collapseInput();
538→        }
539→        return;
540→      }
541→
542→      // Ctrl+I - expand input and focus with cursor at end
543→      if (e.key === 'i' || e.key === 'I') {
544→        if (e.ctrlKey || e.metaKey) {
545→          // Only respond when input is collapsed
546→          if (container.classList.contains(COLLAPSED_CLASS)) {
547→            e.preventDefault();
548→            e.stopPropagation();
549→            expandInputWithCursorAtEnd();
550→          }
551→        }
552→        return;
553→      }
554→    },
555→    { signal, capture: true }, // capture phase to ensure we intercept before other handlers
556→  );
557→
558→  // Listen for language changes and update placeholder text
559→  browser.storage.onChanged.addListener((changes, areaName) => {
560→    if ((areaName === 'sync' || areaName === 'local') && changes[StorageKeys.LANGUAGE]) {
561→      // Update all placeholder text
562→      document.querySelectorAll<HTMLDivElement>(`.${PLACEHOLDER_CLASS}`).forEach((placeholder) => {
563→        const span = placeholder.querySelector('span');
564→        if (span) {
565→          span.textContent = getTranslationSync('inputCollapsePlaceholder') || 'Message Gemini';
566→        }
567→      });
568→    }
569→  });
570→
571→  // Try once immediately
572→  const container = getInputContainer();
573→  if (container) {
574→    // trigger logic manually just in case
575→    container.classList.remove('gv-processed');
576→  }
577→}
