579→/**
580→ * Check if an element is part of input-related UI (menus, overlays, etc.)
581→ * This prevents collapse when clicking model selector, attachment button, etc.
582→ */
583→function isInputRelatedElement(element: HTMLElement, container: HTMLElement): boolean {
584→  if (!element) return false;
585→
586→  // Check if the element is or is inside known input-related containers
587→  const INPUT_RELATED_SELECTORS = [
588→    // Material/CDK overlays (menus, dialogs, autocomplete dropdowns)
589→    '.cdk-overlay-container',
590→    '.mat-mdc-menu-panel',
591→    '.mat-mdc-dialog-container',
592→    '.ng-trigger',
593→    // Model selector and related UI
594→    '[role="listbox"]',
595→    '[role="option"]',
596→    '[role="combobox"]',
597→    // Attachment and file-related UI
598→    '[data-test-id*="attachment"]',
599→    '[data-test-id*="upload"]',
600→    '[data-test-id*="file"]',
601→  ];
602→
603→  // Check if element matches any of the selectors
604→  for (const selector of INPUT_RELATED_SELECTORS) {
605→    if (element.matches(selector) || element.closest(selector)) {
606→      return true;
607→    }
608→  }
609→
610→  // Additional heuristic: check if element is within a reasonable proximity
611→  // to the input container (within 5 levels up, but not the body/main)
612→  let parent = element.parentElement;
613→  let levels = 0;
614→  while (parent && levels < 5) {
615→    // If we reach body or main, we've gone too far
616→    if (parent.tagName === 'BODY' || parent.tagName === 'MAIN') {
617→      break;
618→    }
619→    // If we find the container, the element is input-related
620→    if (parent === container) {
621→      return true;
622→    }
623→    parent = parent.parentElement;
624→    levels++;
625→  }
626→
627→  return false;
628→}
