630→function expand(container: HTMLElement, moveCursorToEnd: boolean = false) {
631→  if (container.classList.contains(COLLAPSED_CLASS)) {
632→    container.classList.remove(COLLAPSED_CLASS);
633→
634→    // Auto-focus the Quill editor
635→    const editor =
636→      container.querySelector('.ql-editor') ||
637→      container.querySelector('[contenteditable]') ||
638→      container.querySelector('rich-textarea');
639→
640→    if (editor && editor instanceof HTMLElement) {
641→      setTimeout(() => {
642→        editor.focus();
643→        if (moveCursorToEnd && !isInputEmpty(container)) {
644→          moveCursorToEndOfElement(editor);
645→        }
646→      }, 0);
647→    }
648→  }
649→}
650→
651→/**
652→ * Moves the cursor to the end of the content in a contenteditable element
653→ */
654→function moveCursorToEndOfElement(element: HTMLElement): void {
655→  const selection = window.getSelection();
656→  if (!selection) return;
657→
658→  const range = document.createRange();
659→
660→  const targetNode = element.lastChild || element;
661→
662→  range.selectNodeContents(targetNode);
663→  range.collapse(false); // false = collapse to end
664→
665→  selection.removeAllRanges();
666→  selection.addRange(range);
667→}
668→
669→function tryCollapse(container: HTMLElement) {
670→  // We need a small delay to handle transient states
671→  setTimeout(() => {
672→    // Don't collapse on excluded pages (homepage, new conversation, gems create)
673→    if (shouldDisableAutoCollapse()) {
674→      container.classList.remove(COLLAPSED_CLASS);
675→      return;
676→    }
677→
